import { mkdtemp, rm } from 'node:fs/promises';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { afterEach, describe, expect, it } from 'vitest';
import type { ProjectEvent } from '@agent-foundry/contracts';
import { FileEventStore } from './event-store.js';

const projectId = 'project-cursor';

function makeEvent(id: string, createdAt: string): ProjectEvent {
  return {
    id,
    projectId,
    type: 'node.completed',
    createdAt,
    message: `event ${id}`,
    data: {},
  };
}

const temporaryDirectories: string[] = [];
afterEach(async () => {
  await Promise.all(
    temporaryDirectories.splice(0).map((dir) => rm(dir, { recursive: true, force: true })),
  );
});

async function seededStore(): Promise<{ store: FileEventStore; events: ProjectEvent[] }> {
  const dataDir = await mkdtemp(join(tmpdir(), 'agent-foundry-event-store-'));
  temporaryDirectories.push(dataDir);
  const store = new FileEventStore(dataDir);
  const events = [
    makeEvent('evt-1', '2026-07-14T12:00:00.000Z'),
    makeEvent('evt-2', '2026-07-14T12:00:01.000Z'),
    makeEvent('evt-3', '2026-07-14T12:00:02.000Z'),
    makeEvent('evt-4', '2026-07-14T12:00:03.000Z'),
    makeEvent('evt-5', '2026-07-14T12:00:04.000Z'),
  ];
  for (const event of events) {
    await store.append(event);
  }
  return { store, events };
}

describe('FileEventStore cursor pagination', () => {
  it('returns only events after the given cursor id', async () => {
    const { store, events } = await seededStore();

    const page = await store.list(projectId, 500, events[2]!.id);

    expect(page.map((event) => event.id)).toEqual(['evt-4', 'evt-5']);
  });

  it('falls back to id-ordering when the cursor id is unknown', async () => {
    const { store } = await seededStore();

    const page = await store.list(projectId, 500, 'unknown-cursor-id');

    expect(page.map((event) => event.id)).toEqual(['evt-1', 'evt-2', 'evt-3', 'evt-4', 'evt-5']);
  });

  it('keeps tail-slice behavior when no cursor is given', async () => {
    const { store } = await seededStore();

    const page = await store.list(projectId, 2);

    expect(page.map((event) => event.id)).toEqual(['evt-4', 'evt-5']);
  });
});
